import React, { useState, useEffect } from 'react';
import ClientForm from './components/ClientForm';
import ClientList from './components/ClientList';
import ArticleForm from './components/ArticleForm';
import ArticleList from './components/ArticleList';

const App = () => {
  const [view, setView] = useState('clients'); // clients ou articles

                                                                           // --- CLIENT ---
  const [clients, setClients] = useState([]);
  const [selectedClient, setSelectedClient] = useState(null);

  const fetchClients = async () => {
    const res = await fetch('http://localhost:3001/clients');
    const data = await res.json();
    setClients(data);
    setSelectedClient(null);
  };
  {view === 'clients' && (
    <div>
      <h2>Gestion des Clients</h2>
      <ClientForm selectedClient={selectedClient} onSuccess={fetchClients} />
      <ClientList clients={clients} onSelect={setSelectedClient} />
    </div>
  )}

                                                                          // --- ARTICLE ---
  const [articles, setArticles] = useState([]);
  const [selectedArticle, setSelectedArticle] = useState(null);

  const fetchArticles = async () => {
    try {
      const res = await fetch('http://localhost:3001/articles');
      const data = await res.json();
      
      // ✅ Vérifie que c'est bien un tableau
      if (Array.isArray(data)) {
        setArticles(data);
      } else {
        console.error("La réponse n'est pas un tableau :", data);
        setArticles([]); // pour éviter une erreur
      }
    } catch (err) {
      console.error("Erreur lors du chargement des articles :", err);
      setArticles([]); // fallback si erreur réseau
    }
  };
  

  useEffect(() => {
    if (view === 'clients') {
      fetchClients();
    } else if (view === 'articles') {
      fetchArticles();
    }
  }, [view]);

  return (
    <div className="app-container">
      <h1>Gestion Boucherie</h1>
      <div>
        <button onClick={() => setView('clients')}>Clients</button>
        <button onClick={() => setView('articles')}>Articles</button>
      </div>

     

      {view === 'articles' && (
        <div>
          <h2>Gestion des Articles</h2>
          <ArticleForm selectedArticle={selectedArticle} onSuccess={fetchArticles} />
          <ArticleList articles={articles} onSelect={setSelectedArticle} />
        </div>
      )}
    </div>
  );
};

export default App;
